const Q_COMMERCE_2001=[{"id": "objective>Commerce>2001>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pivot on which the wheel of commerce rotates is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tariff</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">taxation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prices</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pivot on which the wheel of commerce rotates is trade. Commerce is essentially about the exchange of goods and services, and trade is the activity that facilitates this exchange. Therefore, trade is the pivot on which commerce rotates.</div>", "topic": "TRADE (1) : HOME TRADE: WHOLESALE TRADE"}, {"id": "objective>Commerce>2001>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A distinguishing characteristic of labour is that it is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expensive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mobile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cheap</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Labour is the only factors of production that is mobile. labour is mobile in both geographically and occupational from one place or job to another.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2001>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Land as a factor of production does not vary in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Land as a factor of production does not vary in quantity. The quantity of land is fixed, it cannot be increased or decreased. While the quality, nature, and cost of land can vary depending on various factors such as location, fertility, and market conditions, the total quantity of land remains the same.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2001>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following services does a lawyer render?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Industrial services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Indirect services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Direct services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commercial services</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Direct service includes personal services rendered for direct consumption and are paid for directly by those who enjoy the service. Those engage in this form of occupation are: Housemaids, Stewards, Entertainers, Lawyers, Barbers etc.</div>", "topic": "OCCUPATION : MEANING & IMPORTANCE"}, {"id": "objective>Commerce>2001>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The partner that only contributes part of the capital used in the formation and running of a business is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an authoritative partner</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an active partner</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a dormant partner</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a nominal partner</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A dormant partner is a partner who only contributes capital to the business but does not participate in its day-to-day operations or management. They are also known as silent or passive or limited partners. They share in the profits and losses of the business but their role and liability can be limited depending on the partnership agreement.</div>", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES"}, {"id": "objective>Commerce>2001>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major advantages of a credit and thrift cooperative is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it can approach government for loan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it encourages saving habit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there are no legal restrictions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">each member has a vote during meetings</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The services provided to members are: <br/> - encouragement on savings habit <br/> - provision of loan facilities <br/> - enlightenment of members <br/> - payment of dividend <br/> - foster close relationship between members <br/> - render help in time of need <br/> - encourage increased standard of living.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2001>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A form of ownership which exploits the strength of one partner to remedy the weaknesses of the other is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">joint partnership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cooperative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">corporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint venture</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Joint venture is a business that involves two or independent individual which the business is based or run.</div>", "topic": "BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES"}, {"id": "objective>Commerce>2001>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At the collapse of a business enterprise, the person appointed to dispose asset is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a broker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an auctioneer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a liquidator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an auditor</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A liquidator is the person appointed to sell off a collapsed firm assets in order to settle its creditor's or share holders.</div>", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION"}, {"id": "objective>Commerce>2001>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Entrusting the management of a company to the courts to enable the settlement of the company's obligations is an indication of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">distress</div>", "<div style=\"font-family:Cambria;font-size:17px;\">closure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bankruptcy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquidation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bankruptcy is a legal process that allows a company to reorganize its finances or to liquidate its assets. When a company is in bankruptcy, the courts appoint a trustee to manage the company's assets and to oversee the settlement of its debts. <br/>  <br/> The trustee may sell the company's assets to pay off its debts, or the company may be reorganized and allowed to continue operating. The outcome of the bankruptcy process depends on the specific circumstances of the company. <br/>  <br/> Entrusting the management of a company to the courts to enable the settlement of the company's obligations is an indication that the company is in financial distress and may be headed for bankruptcy.</div>", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION"}, {"id": "objective>Commerce>2001>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The financial instrument for borrowing in which the collateral is usually more than the amount borrowed is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trust certificate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">detachable warrant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mortgage bond</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convertible securities</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mortgage bond is the financial instrument on properties which are always more than amount to be borrowed.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2001>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Personal savings  <br/> II. Retained earnings  <br/> III. Accrued Taxes  <br/>  <br/> Which of the items above constitute internal source of financing for companies?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Internal sources of finance are funds that come from within the business. Personal savings and retained earnings are examples of internal sources of finance. Personal savings refers to the money that the owner of the business has saved up and decides to invest in the business. Retained earnings are the profits that the company has earned and decided to reinvest in the business rather than distribute to shareholders. Accrued taxes, on the other hand, are not a source of finance but a liability.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2001>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between total current assets and total current liabilities of a business is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quick ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquidity ration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">working capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">circulating capital</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The working capital of a business is the difference between total current assets and total current liability.</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2001>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the balance sheet below to answer the question that follows.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The capital employed is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦1,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,370</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦140</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦50</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capital employed: The three (3) views are: <br/> -  The total cost of the business, both fixed and current i.e. fixed assets plus current assets. <br/> -    Total assets less debt (debtors) <br/> -  Total assets less current liabilities.  <br/>  <br/> However, here the first view is upheld. Therefore, Capital employed is the total assets which is #1370. <br/> </div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2001>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the balance sheet below to answer the question that follows.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The capital owned is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦2,740</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,350</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,150</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦570</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capital owned = Capital + Profit  <br/> i.e Capital + Add. capital + Net profit <br/>           140 +350+ 80  <br/>                     = ₦570</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2001>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the reasons why wholesaling must continue is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the tax paid by wholesalers on their profit enhances national revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">by creating artificial scarcity, the wholesaler is enhancing competition in the economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the wholesaler provides technical advice to the retailer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the gap between manufacturers and retailers is reduced by wholesalers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wholesalers bridge this gap by buying from manufacturers in bulk quantities due to their high purchasing power and then selling in smaller quantities to retailers with lower purchasing power.</div>", "topic": "TRADE (1) : HOME TRADE: WHOLESALE TRADE"}, {"id": "objective>Commerce>2001>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A merchant wholesaler is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">del-credere agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a broker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rack jobber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a factor</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A rack jobber is a specific type of merchant wholesaler who specializes in maintaining and stocking product displays (racks) in retail stores. They own the products they sell and provide a full range of services, including inventory management and shelf stocking.</div>", "topic": "TRADE (1) : HOME TRADE: WHOLESALE TRADE"}, {"id": "objective>Commerce>2001>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A pro-forma invoice is sent to inform a buyer about</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quantity of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">designation of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quality of goods</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A pro-forma invoice is sent to inform the buyer on the prices of goods. It is used to serve as a quotation and serves as a reply to enquires.</div>", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING"}, {"id": "objective>Commerce>2001>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The balance of payments of countries is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a record of imports and exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a systematic record of transactions among countries at a given time</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the current and the capital accounts and their payments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the trade relationships and payments among nations</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Balance of Payments is a statement or record showing the relationship between a country's total payments to other countries and its total receipts from them in a year.</div>", "topic": "TRADE ( 2) : BALANCE OF PAYMENT"}, {"id": "objective>Commerce>2001>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major procedures in the purchase and sale of goods are enquiry</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quotation, order and invoice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">placement, order and invoice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bargain, order and invoice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">order, sale and invoice</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major procedures in the purchase and sale of goods are enquiry, quotation, order, and invoice. Enquiry is when the buyer asks about the availability and price of goods. Quotation is the response from the seller with the price and terms of sale. Order is the buyer's request to purchase the goods. Invoice is the document sent by the seller to the buyer, detailing the goods sold and the amount due.</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE"}, {"id": "objective>Commerce>2001>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer the question that follows  <br/>  Mr. Awala is a retailer of a single product. He sells at the standard price. He gives a trade discount of 5%, quantity discount of 3% for a volume above 1000 units and a cash discount of 2/10 net 30, the existing selling price of the product is ₦100 per unit. Mr. Bacus purchased 1500 units of the product on credit and promised to pay Mr. Awala in cash in the first 10 days after purchase <br/>  <br/> The trade discount receivable by Mr. Bacus is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦4,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦7,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦10,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦12,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trade discount = 5% of 1500 × ₦100 <br/>                                     =  ₦7,500</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT"}, {"id": "objective>Commerce>2001>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer the question that follows  <br/>  Mr. Awala is a retailer of a single product. He sells at the standard price. He gives a trade discount of 5%, quantity discount of 3% for a volume above 1000 units and a cash discount of 2/10 net 30, the existing selling price of the product is ₦100 per unit. Mr. Bacus purchased 1500 units of the product on credit and promised to pay Mr. Awala in cash in the first 10 days after purchase <br/> If Mr. Bacus fulfils his promise, he will be entitled to a cash discount of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦2,760</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦3,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦6,500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦9,500</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2/10 means 2% cash discount if the money is paid on or before  10 ten days  <br/>  <br/>  2/100 × 1500 × 100 = ₦3,000</div>", "topic": "TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>2001>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bank Giro is a method of settling debt from a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">customer to a bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank to a customer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">customer to another</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank to another</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bank Giro is a method of transferring money from one bank account to another, typically used to pay bills. Therefore, it is a method of settling debt from a customer to another entity, not necessarily a bank.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2001>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Warehousing is a productive function because it increases the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quantity of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">utility of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quality of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price of goods</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Warehousing does not increase the quantity, quality, or price of goods. However, it does increase the utility of goods by providing a place for them to be stored until they are needed. This is known as time utility, as it allows goods to be available at the right time.</div>", "topic": "AIDS TO TRADE: WAREHOUSING: : ADVANTAGES & DISADVANTAGES OF WAREHOUSING"}, {"id": "objective>Commerce>2001>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A factor necessary for sitting a warehouse is nearness to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A warehouse should ideally be located near consumers. This is because the main function of a warehouse is to store goods until they are needed by consumers. Having a warehouse near consumers reduces the time and cost of transportation, making the goods readily available when needed.</div>", "topic": "AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE"}, {"id": "objective>Commerce>2001>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pooling of risk in insurance means that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">compensations are paid out of a common fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two people can pool their risks to be insured</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two insurance companies can buy two policies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insurance companies should encourage taking risk</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Risk pooling in insurance means that there are many contributors to help spread the financial risks from expensive claims more evenly.</div>", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES"}, {"id": "objective>Commerce>2001>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The indemnification of Ama by his insurance company after a fire disaster means that he</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">has been guaranteed by the insurance company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">will be cleared of any fault by the insurance company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has been covered by the insurance company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">will be covered to the limit of the amount in the policy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Indemnification means that the insured, is given some form of compensation to the limit of the amount in the policy taken.</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2001>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major difference between insurance and assurance is that while insurance</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">takes care of uncertainty, assurance takes care of risks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">takes care of risks, assurance takes care uncertainty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hinges on probabilities, assurance is based on possibilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is about indemnity, assurance is about life in the future</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between insurance and assurance is that insurance is based on probability, that is, the event may or may not occur. For example, Motor vehicle, fire accident etc while Assurance is based on possibility, that is, the event will occur e.g. Death.</div>", "topic": "AIDS TO TRADE: INSURANCE : TYPES"}, {"id": "objective>Commerce>2001>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A documentary bill will normally be accompanied by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sales invoice, bill of lading and insurance certificate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clean bill, bill of lading and insurance certificate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bill of lading, consular invoice and insurance certificate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consular invoice, FOB certificate and bill of lading</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A documentary bill is a type of bill of exchange that is accompanied by documents that prove the shipment of goods. These documents typically include a sales invoice, a bill of lading, and an insurance certificate. The sales invoice is a document that shows the details of the sale, the bill of lading is a document issued by a carrier that details a shipment of merchandise and gives title of that cargo to a specified party, and the insurance certificate is a document that verifies the existence of an insurance policy.</div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>2001>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best describes the classification of computers?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mini-computer, speed and size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Micro-computer, cost and abilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mini-computer, micro-computer and work station</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mini-computer, hybrid and digital</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Computers can be classified based on their size and power. The main types of computers are mini-computers, micro-computers, and workstations. Mini-computers are smaller than mainframe computers but larger than micro-computers. They are powerful enough to support multiple users. Micro-computers are the most common type of computers and include personal computers and laptops. Workstations are powerful single-user computers used for tasks that require a lot of computational power such as graphic design and digital content creation.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2001>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The temporary working area of a central processing unit is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CD-ROM</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CD-RAM</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ROM</div>", "<div style=\"font-family:Cambria;font-size:17px;\">RAM</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">RAM stands for Random Access Memory. It is a volatile memory that losses its contents when the computer or hardware device losses power.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : ACTIVITIES IN COMPUTER"}, {"id": "objective>Commerce>2001>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The significance of money to modern economic systems is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is used as a means of payment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promotes specialization and exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">measures value and promotes exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">causes inflation and deflation in the economy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Money is a measures of how much something is worth and then also used as a means of exchanging goods and services.</div>", "topic": "MONEY : FUNCTIONS OF MONEY"}, {"id": "objective>Commerce>2001>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One major characteristic of credit unions and thrift societies is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the legal processes involved in their formation are rigid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">membership is compulsory to people in the same line of business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the contribution of every member depends on the member's ability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a minimum of ten people in the same line of business can form the union</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristics of credit unions and thrift societies are: <br/> - perpetual existence <br/> - registered as  a limited liability <br/> - democratic in nature i.e each member is entitled to one vote,irrespective of the total shares <br/> - the objective is on promote members <br/> - managed by a committee <br/> - profit is shared based on patronage  etc.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE"}, {"id": "objective>Commerce>2001>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian Stock Exchange publishes a daily official list that gives full information on the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">method of transactions agreed to by members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of participating members in a day</div>", "<div style=\"font-family:Cambria;font-size:17px;\">changes in the prices and earnings of securities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">changes in the official rules set by the market</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigeria Stock Exchange has been operating an Automated Trading System (ATS) since April 27, 1999, with dealers trading through a computer network. Trading on the Exchange starts at 9:30am and closes at 2:30 pm every Monday - Friday. Market prices, along with an All-share index, NSE 30, and sector indices, are published daily in the Stock Exchange Daily Official List due to changes in the prices and earnings of securities <br/> , The Nigerian Stock Exchange CAPNET (an intranet facility), newspapers, and on the stock market page of the Reuters Electronic Contributor System.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2001>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main factors that determine the value of a stock on the Stock Exchange are dividend and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the psychology of the market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital gain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital appreciation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warrant payment</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main factors that determine the value of a stock on the Stock Exchange are the dividend and capital gain. Dividend is the distribution of a portion of a company's earnings to its shareholders. Capital gain is the rise in the value of a capital asset (investment or real estate) that gives it a higher worth than the purchase price. The psychology of the market and warrant payment do not directly determine the value of a stock.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2001>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the main objectives of the second-tier Securities Market in Nigeria is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">achieve a realistic exchange rate for the naira</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eliminate currency dealings in the black market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assist companies to raise capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attract investment flow</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the main objectives of the second-tier Securities Market in Nigeria is to assist companies to raise capital. This market provides a platform for small and medium-sized companies to raise long-term capital at lower costs. It does not aim to achieve a realistic exchange rate for the naira, eliminate currency dealings in the black market, or attract investment flow.</div>", "topic": "STOCK EXCHANGE : SECOND- TIER SECURITIES MARKET"}, {"id": "objective>Commerce>2001>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The activities aimed at finding out customers' needs and satisfaction can be described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">socio-marketing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">macro- marketing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">micro-marketing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conceptual marketing</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Micro-marketing involves tailoring products and marketing programs to the needs and wants of specific individuals and local customer segments. It includes local marketing and individual marketing. Therefore, the activities aimed at finding out customers' needs and satisfaction can be described as micro-marketing.</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>2001>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most effective type of advertising for branded products is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">direct advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indirect advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">informative advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competitive advertising</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Informative advertising is often used when launching a new product, or for an updated or relaunched product. The objective is to develop initial demand for a good, service, organization, or cause. It is used when a new product is put on the market on when an old product has been re-launched or updated.</div>", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA"}, {"id": "objective>Commerce>2001>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question  <br/> Companies I, II, III and IV produce and sell electronic videos. Company I sells its video for ₦14,000 each and offers advice on how to fix and operate them. Company II sells at ₦14,000 and its representatives go to install at no additional cost. Company III sells at ₦15,500 and offers  credit sales at ₦15,500 per video while company IV sells at ₦15,000 each. <br/>  <br/> Which of these companies are more engaged in public relation activities?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Public relation is a device and strategy which the sellers adopt in order to endear himself to the customer in order to win public acceptance. Therefore, Company 1 and II are more involved public relation activities.</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>2001>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question  <br/> Companies I, II, III and IV produce and sell electronic videos. Company I sells its video for ₦14,000 each and offers advice on how to fix and operate them. Company II sells at ₦14,000 and its representatives go to install at no additional cost. Company III sells at ₦15,500 and offers  credit sales at ₦15,500 per video while company IV sells at ₦15,000 each. <br/> Which of these companies offers after-sales services?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">After-sales service refers to any support provided after a customer has purchased a product. This can include installation, maintenance, and advice on how to use the product. In the given scenario, both Company I and II offer after-sales services. Company I offers advice on how to fix and operate the videos, while Company II installs the videos at no additional cost. However, since the options only include one company at a time, the correct answer I and II</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>2001>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer the question that follows  <br/> Musa rented a room to Adamu for ₦1,500 and ₦1,000 part- payment was made. Adamu brought Audu and Jacob his friends to stay in the room.The two  friends latter paid the balance of ₦500 to Musa. <br/>  <br/> Who are the parties to the contract of renting the room?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Musa and Jacob</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Musa and Audu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adamu and Musa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Audu and Jacob</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Musa and Adamu because the both went into the contract from the beginning or the contract is not binding on the two friends.Therefore, Musa is the Offeror(the person making the offer) while Adamu is the offeree ( the person accepting the offer).</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>2001>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer the question that follows  <br/> Musa rented a room to Adamu for ₦1,500 and ₦1,000 part- payment was made. Adamu brought Audu and Jacob his friends to stay in the room.The two  friends latter paid the balance of ₦500 to Musa. <br/> Who is the offeree in this contract?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Musa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Audu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adamu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jacob</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adamu is the offeree i.e he is the person accepting the offer or agrees to the terms of the contract between him and Musa.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>2001>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The maximum number of shareholders in a public liability company is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">twenty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fifty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one hundred</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unlimited</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A public limited company is a type of company that is permitted to offer its shares to the public. They can have an unlimited number of shareholders. Hence, the correct answer is 'unlimited'.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES"}, {"id": "objective>Commerce>2001>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One way by which government reduces the repatriation of capital is through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nationalization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">divestiture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indigenization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">naturalization</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Indigenization is a policy by which a government encourages the citizens of its country to gain control over foreign-owned or multinational corporations and industries. This reduces the repatriation of capital as the control of the business is in the hands of the locals. Hence, the correct answer is 'indigenization'.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : FACTORS"}, {"id": "objective>Commerce>2001>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major functions of a chamber of commerce is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">promote and protect trade, industry and agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advise members on regulations of other countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">settle disputes that arise out of trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">publish books and periodicals desired by members</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The functions of chamber of commerce are: <br/> - to organise trade fairs and exhibitions <br/> - to promote home and foreign trade <br/> - to co-operate with other chambers of commerce <br/> - to collect and disseminate information to members <br/> - settlement of disputes among members <br/> - they acts as watchdogs in the administrations of government laws <br/> - Maintain commercial museums  etc.</div>", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE"}, {"id": "objective>Commerce>2001>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Departmentalization is an aspect of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">planning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organizing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">directing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">controlling</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Departmentalization means grouping activities and people into departments, making it possible to expand organizations, at least in theory, to an indefinite degree. Departmentalization refers to the formal structure of the organization, composed of various departments and managerial positions and their relationships with each other.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2001>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A functional organizational structure is where</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">staff performing the same functions are grouped together</div>", "<div style=\"font-family:Cambria;font-size:17px;\">departments performing similar functions are grouped together</div>", "<div style=\"font-family:Cambria;font-size:17px;\">activities of similar nature are grouped together</div>", "<div style=\"font-family:Cambria;font-size:17px;\">staff performing similar functions are grouped together</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A functional organizational structure is where staff performing the same functions are grouped together. This type of structure groups individuals by specific functions performed. Individuals within the functional division of an organization tend to perform a specialized set of tasks, for instance, the engineering department would be staffed only with software engineers.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2001>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the line type of organizational structure.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the lines of authority are vertical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is the application of division of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">specialization is carried to a maximum degree</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the lines of authority are horizontal</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Line organizational structure is the direct working relationship between the subordinates and superiors in which the authority and responsibilities flow from the top to the lowest. The line organisation represents the structure in a direct vertical relationship through which authority flows. It is the simplest form of organisation structure and is also known as scalar or military organisation. Under this, the line of authority flows vertically downward from top to bottom throughout the organization.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2001>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Proper disposal of waste by business firms is one way of discharging their</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">responsibility to government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">environmental responsibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">community responsibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">responsibility to customer</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Environmental Responsibilities for Business Under the Environmental Responsibility of the corporate, it is expected to operate in a manner that protects the environment. Going beyond business activities and taking care of the environment can bring business benefits.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : POLLUTION"}, {"id": "objective>Commerce>2001>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the obstacles to achieving the objectives of ECOWAS is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lack of a common currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colonial linkages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sovereignty of states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">language differences</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the obstacles to achieving the objectives of ECOWAS (Economic Community of West African States) is the sovereignty of states. This is because each member state of ECOWAS has its own laws, regulations, and policies, which can sometimes conflict with the objectives of ECOWAS. Sovereignty refers to the authority of a state to govern itself, and it can be a barrier to regional integration efforts like ECOWAS.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>2001>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the main objectives of establishing Niger-River Basin Commission was to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">embark on a comprehensive survey of the available water resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carry out research for the development of fresh water fisheries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">develop infrastructure to facilitate economic activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote trade among member-states to improve standards of living</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the main objectives of establishing the Niger-River Basin Commission was to embark on a comprehensive survey of the available water resources. This is because the Niger River is a major water resource for the countries in the region, and understanding its resources is crucial for planning and managing its use. The commission was established to promote cooperation among the member states in managing the river's resources.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}];
